import{_ as s,c as a,o as e,d as n}from"./app.661b9247.js";const g=JSON.parse('{"title":"Koa框架前置JS知识","description":"","frontmatter":{},"headers":[{"level":2,"title":"Express、Koa1.x、Koa2.x区别","slug":"express、koa1-x、koa2-x区别","link":"#express、koa1-x、koa2-x区别","children":[{"level":3,"title":"最大的区别就是内部实现异步的方式不同","slug":"最大的区别就是内部实现异步的方式不同","link":"#最大的区别就是内部实现异步的方式不同","children":[]},{"level":3,"title":"第二大的区别就是重量级不同","slug":"第二大的区别就是重量级不同","link":"#第二大的区别就是重量级不同","children":[]}]},{"level":2,"title":"使用 Babel 实现 Async 方法","slug":"使用-babel-实现-async-方法","link":"#使用-babel-实现-async-方法","children":[]}],"relativePath":"Document/Node后端框架开发/Koa框架/Koa框架前置JS知识.md","lastUpdated":1670959281000}'),r={name:"Document/Node后端框架开发/Koa框架/Koa框架前置JS知识.md"},o=n(`<h1 id="koa框架前置js知识" tabindex="-1">Koa框架前置JS知识 <a class="header-anchor" href="#koa框架前置js知识" aria-hidden="true">#</a></h1><p><strong>Express</strong>：Express是第一代最流行的web框架，它对Node.js的http进行了封装 但是它是&#39;基于ES5&#39;的语法，内部实现异步代码，只有一个方法：&#39;回调&#39;</p><p><strong>koa1.x</strong>：基于ES6开发，使用generator实现异步，generator实现异步比回调简单不少，但generator的本意并不是异步</p><p><strong>koa2.x</strong>：基于ES7开发：koa2.x完全使用Promise并配合async实现异步</p><p>所以学习Koa需要ES6和ES7的知识</p><h2 id="express、koa1-x、koa2-x区别" tabindex="-1">Express、Koa1.x、Koa2.x区别 <a class="header-anchor" href="#express、koa1-x、koa2-x区别" aria-hidden="true">#</a></h2><h3 id="最大的区别就是内部实现异步的方式不同" tabindex="-1">最大的区别就是内部实现异步的方式不同 <a class="header-anchor" href="#最大的区别就是内部实现异步的方式不同" aria-hidden="true">#</a></h3><ul><li><strong>Express</strong>使用回调函数实现异步, 容易出现回调地狱问题, 但是语法更老兼容性更好</li><li><strong>Koa1.x</strong>使用generator实现异步, 解决了回调地域问题, 但是generator的本意并不是异步</li><li><strong>Koa2.x</strong>使用Promise并配合async来实现异步, 解决了回调地域问题, 但是语法太新兼容性不好</li></ul><h3 id="第二大的区别就是重量级不同" tabindex="-1">第二大的区别就是重量级不同 <a class="header-anchor" href="#第二大的区别就是重量级不同" aria-hidden="true">#</a></h3><ul><li>Express中内置了很多封装好的功能，而Koa中将这些功能都封装到了独立的模块中，想要使用这些功能必须先安装对应的模块才能使用，所以Koa比Express更轻量级</li></ul><h2 id="使用-babel-实现-async-方法" tabindex="-1">使用 Babel 实现 Async 方法 <a class="header-anchor" href="#使用-babel-实现-async-方法" aria-hidden="true">#</a></h2><p>要在 node &lt; 7.6 版本的 Koa 中使用 <code>async</code> 方法, 我们推荐使用 <a href="https://www.babeljs.cn/docs/usage/babel-register/" target="_blank" rel="noreferrer">babel&#39;s require hook</a></p><div class="language-js line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki one-dark-pro"><code><span class="line"><span style="color:#61AFEF;">require</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;babel-register&#39;</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// 应用的其余 require 需要被放到 hook 后面</span></span>
<span class="line"><span style="color:#C678DD;">const</span><span style="color:#ABB2BF;"> </span><span style="color:#E5C07B;">app</span><span style="color:#ABB2BF;"> </span><span style="color:#56B6C2;">=</span><span style="color:#ABB2BF;"> </span><span style="color:#61AFEF;">require</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;./app&#39;</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>要解析和编译 async 方法, 你至少应该有 <a href="https://www.babeljs.cn/docs/plugins/transform-async-to-generator/" target="_blank" rel="noreferrer">transform-async-to-generator</a> 或 <a href="https://www.babeljs.cn/docs/plugins/transform-async-to-module-method/" target="_blank" rel="noreferrer">transform-async-to-module-method</a> 插件.</p><p>例如, 在你的 <code>.babelrc</code> 文件中, 你应该有:</p><div class="language-json line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki one-dark-pro"><code><span class="line"><span style="color:#ABB2BF;">{</span></span>
<span class="line"><span style="color:#ABB2BF;">  </span><span style="color:#E06C75;">&quot;plugins&quot;</span><span style="color:#ABB2BF;">: [</span><span style="color:#98C379;">&quot;transform-async-to-generator&quot;</span><span style="color:#ABB2BF;">]</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>你也可以用 <a href="https://www.babeljs.cn/docs/plugins/preset-env/" target="_blank" rel="noreferrer">env preset</a> 的 target 参数 <code>&quot;node&quot;: &quot;current&quot;</code> 替代.</p>`,17),l=[o];function t(p,c,i,d,u,b){return e(),a("div",null,l)}const y=s(r,[["render",t]]);export{g as __pageData,y as default};
